const drop=['unsubscribe','newsletter','% off','sale ends','webinar','blog post','digest','password reset','verify your email','sign in to','log in to'];
const keep=['invoice','receipt','subscription','renew','payment','billing','charged','your plan','plan renews','auto-renew','order confirmation','your subscription'];
const out=[];
for(const it of $input.all()){const j=it.json;const s=((j.Subject||j.subject||'')+' '+(j.snippet||'')+' '+(j.From||j.from||'')).toLowerCase();
if(keep.some(k=>s.includes(k))&&!drop.some(d=>s.includes(d)))out.push({json:j});}
return out;

// Agent ka output text mein aata hai — parse karo
const raw = $input.first().json.output || $input.first().json.text || '';

let parsed;
try {
  const clean = raw.replace(/```json|```/gi, '').trim();
  parsed = JSON.parse(clean);
} catch(e) {
  return [{ json: {
    is_billing: true,
    Vendor: 'Parse Failed',
    _target: 'review',
    _parse_error: e.message,
    _raw: raw.slice(0, 500)
  }}];
}

if (!parsed.is_billing) {
  return [{ json: { ...parsed, _target: 'skip' } }];
}

const amount = Number(parsed.Amount);
const me = Number(parsed['Monthly Equivalent']);
const conf = Number(parsed.Confidence);

if (isNaN(amount) || amount < 0) parsed.Amount = null;
if (isNaN(me) || me < 0)         parsed['Monthly Equivalent'] = 0;

parsed['Est. Annual Cost'] = Math.round((isNaN(me) ? 0 : me) * 12 * 100) / 100;

if (parsed['Renewal Date'] && !/^\d{4}-\d{2}-\d{2}$/.test(parsed['Renewal Date'])) {
  parsed['Renewal Date'] = null;
  parsed['Days to Renewal'] = null;
}

if (isNaN(conf) || conf < 0.6) {
  parsed._target = 'review';
}

parsed.Status = parsed.Status || 'new';

return [{ json: parsed }];

// ── Rows from Upsert Dashboard (this run) ────────────────────────────────
const all = $input.all()
  .map(x => x.json)
  .filter(r => r.Vendor && r.Vendor !== 'Parse Failed');

// ── Aggregate numbers ─────────────────────────────────────────────────────
let totalMonthly = 0, totalAnnual = 0, wasteAnnual = 0, unused = 0, renew30 = 0;
const flagged = [];

for (const r of all) {
  const me  = Number(r['Monthly Equivalent'] || 0);
  const ann = Number(r['Est. Annual Cost']   || me * 12 || 0);
  totalMonthly += me;
  totalAnnual  += ann;

  const wt = (r['Waste Type'] || 'OK').toUpperCase();
  if (wt !== 'OK' && wt !== '') { wasteAnnual += ann; flagged.push(r); }
  if (wt === 'UNUSED' || wt === 'ZOMBIE') unused++;

  const dtr = Number(r['Days to Renewal']);
  if (!isNaN(dtr) && dtr >= 0 && dtr <= 30) renew30++;
}

flagged.sort((a, b) =>
  Number(b['Est. Annual Cost'] || 0) - Number(a['Est. Annual Cost'] || 0)
);

const cur   = 'USD';
const brand = 'YOUR_BRAND_NAME';
const top   = flagged.slice(0, 15);

const fmt = n => Number(Math.round(n * 100) / 100).toLocaleString('en-US');

const badgeColor = wt => {
  if (wt === 'ANNUAL_RENEWAL') return '#dc2626';
  if (wt === 'RENEWAL_SOON')   return '#d97706';
  if (wt === 'UNUSED')         return '#7c3aed';
  if (wt === 'ZOMBIE')         return '#6b21a8';
  return '#6b7280';
};

const tableRows = top.map(r => {
  const wt = (r['Waste Type'] || 'OK').toUpperCase();
  return `
  <tr>
    <td style="padding:8px 12px;border-bottom:1px solid #f1f5f9;font-weight:500">${r.Vendor || '—'}</td>
    <td style="padding:8px 12px;border-bottom:1px solid #f1f5f9;color:#64748b">${r.Category || '—'}</td>
    <td style="padding:8px 12px;border-bottom:1px solid #f1f5f9">
      <span style="display:inline-block;padding:2px 8px;border-radius:12px;font-size:11px;font-weight:700;color:#fff;background:${badgeColor(wt)}">${wt}</span>
    </td>
    <td style="padding:8px 12px;border-bottom:1px solid #f1f5f9;font-weight:600;color:#0f172a">${cur} ${fmt(Number(r['Est. Annual Cost'] || 0))}/yr</td>
    <td style="padding:8px 12px;border-bottom:1px solid #f1f5f9;font-size:13px;color:#475569">${r['Recommended Action'] || '—'}</td>
    <td style="padding:8px 12px;border-bottom:1px solid #f1f5f9;font-size:12px;color:#94a3b8">${r['Renewal Date'] || '—'}</td>
  </tr>`;
}).join('');

const statBox = (label, value, color) =>
  `<td style="width:25%;padding:8px;text-align:center">
    <div style="background:#fff;border:1px solid #e2e8f0;border-radius:8px;padding:14px 8px">
      <div style="font-size:22px;font-weight:800;color:${color}">${value}</div>
      <div style="font-size:11px;color:#64748b;margin-top:4px">${label}</div>
    </div>
  </td>`;

const html = `
<div style="font-family:Arial,sans-serif;max-width:680px;margin:auto;color:#1e293b;background:#f8fafc;padding:20px">
  <div style="background:#0f172a;color:#fff;padding:24px 28px;border-radius:12px 12px 0 0">
    <div style="font-size:11px;opacity:.6;letter-spacing:.06em;text-transform:uppercase">
      ${brand} &middot; Weekly SaaS Waste Audit &middot; ${new Date().toLocaleDateString('en-US',{month:'long',day:'numeric',year:'numeric'})}
    </div>
    <div style="font-size:28px;font-weight:800;margin-top:8px;line-height:1.2">
      ${cur} ${fmt(wasteAnnual)}<span style="font-size:15px;font-weight:400;opacity:.7"> /year potentially recoverable</span>
    </div>
    <div style="font-size:13px;opacity:.65;margin-top:6px">
      ${all.length} subscriptions tracked &nbsp;&bull;&nbsp; Total spend ${cur} ${fmt(totalAnnual)}/yr &nbsp;&bull;&nbsp; ${flagged.length} flagged
    </div>
  </div>
  <table style="width:100%;border-collapse:separate;border-spacing:8px;background:#f1f5f9;padding:12px">
    <tr>
      ${statBox('Total Subscriptions', all.length, '#0f172a')}
      ${statBox('Flagged Issues', flagged.length, '#dc2626')}
      ${statBox('Renewing in 30d', renew30, '#d97706')}
      ${statBox('Possibly Unused', unused, '#7c3aed')}
    </tr>
  </table>
  <div style="background:#fff;border:1px solid #e2e8f0;border-radius:0 0 12px 12px;padding:24px">
    <p style="margin:0 0 18px;font-size:14px;color:#334155">
      Out of <b>${all.length}</b> subscriptions costing <b>${cur} ${fmt(totalMonthly)}/month</b>
      (${cur} ${fmt(totalAnnual)}/year), we flagged <b>${flagged.length} item(s)</b> worth
      <b>${cur} ${fmt(wasteAnnual)}/year</b> in potential waste.
      ${renew30 > 0 ? `<b>${renew30}</b> subscription(s) renew within 30 days — review before auto-charge.` : ''}
    </p>
    ${top.length > 0 ? `
    <table style="border-collapse:collapse;width:100%;font-size:13px">
      <thead>
        <tr style="background:#f8fafc;text-align:left;font-size:11px;color:#64748b;text-transform:uppercase;letter-spacing:.05em">
          <th style="padding:10px 12px;border-bottom:2px solid #e2e8f0">Vendor</th>
          <th style="padding:10px 12px;border-bottom:2px solid #e2e8f0">Category</th>
          <th style="padding:10px 12px;border-bottom:2px solid #e2e8f0">Issue</th>
          <th style="padding:10px 12px;border-bottom:2px solid #e2e8f0">Annual Cost</th>
          <th style="padding:10px 12px;border-bottom:2px solid #e2e8f0">Action</th>
          <th style="padding:10px 12px;border-bottom:2px solid #e2e8f0">Renewal</th>
        </tr>
      </thead>
      <tbody>${tableRows}</tbody>
    </table>` : '<p style="color:#94a3b8;font-style:italic;font-size:13px">No flagged items this week — all subscriptions look healthy.</p>'}
    <div style="margin-top:16px;padding:12px 16px;background:#f8fafc;border:1px solid #e2e8f0;border-radius:8px;font-size:13px">
      <span style="margin-right:24px">Monthly: ${cur} ${fmt(totalMonthly)}</span>
      <span style="margin-right:24px">Annual: ${cur} ${fmt(totalAnnual)}</span>
      <span>Recoverable: ${cur} ${fmt(wasteAnnual)}</span>
    </div>
    <p style="font-size:11px;color:#94a3b8;margin-top:16px;border-top:1px solid #f1f5f9;padding-top:12px">
      Email-only detection. Charges billed directly to a card without email confirmation are not captured here.
      Auto-generated on ${new Date().toISOString().split('T')[0]}.
    </p>
  </div>
</div>`;

return [{
  json: {
    subject : `${brand} SaaS Audit — ${cur} ${fmt(wasteAnnual)}/yr recoverable · ${all.length} subs`,
    html    : html,
    stats   : {
      totalMonthly : Math.round(totalMonthly * 100) / 100,
      totalAnnual  : Math.round(totalAnnual  * 100) / 100,
      wasteAnnual  : Math.round(wasteAnnual  * 100) / 100,
      count        : all.length,
      flaggedCount : flagged.length,
      renew30,
      unused
    }
  }
}];
